import java.util.*;

public class CreationalPatterns {

    // ── SINGLETON — one instance, globally accessible ──────────────────
    static class DatabaseConnection {
        private static volatile DatabaseConnection instance;
        private final String url;

        private DatabaseConnection(String url) {
            this.url = url;
            System.out.println("DB connected: " + url);
        }

        // Double-checked locking — thread-safe, lazy initialisation
        public static DatabaseConnection getInstance() {
            if (instance == null) {
                synchronized (DatabaseConnection.class) {
                    if (instance == null) {
                        instance = new DatabaseConnection("jdbc:mysql://localhost/app");
                    }
                }
            }
            return instance;
        }

        public String getUrl() { return url; }
    }

    // ── FACTORY METHOD — subclass decides which object to create ───────
    abstract static class Notification {
        abstract void send(String message);
        // Template method using factory method
        void notify(String message) {
            System.out.print("[");
            send(message);
            System.out.println("]");
        }
    }
    static class EmailNotification extends Notification {
        void send(String msg) { System.out.print("Email: " + msg); }
    }
    static class SMSNotification extends Notification {
        void send(String msg) { System.out.print("SMS: " + msg); }
    }
    static class PushNotification extends Notification {
        void send(String msg) { System.out.print("Push: " + msg); }
    }

    // Factory — centralises creation logic
    static Notification createNotification(String type) {
        return switch (type.toLowerCase()) {
            case "email" -> new EmailNotification();
            case "sms"   -> new SMSNotification();
            case "push"  -> new PushNotification();
            default -> throw new IllegalArgumentException("Unknown type: " + type);
        };
    }

    // ── BUILDER — step-by-step construction of complex objects ─────────
    static class HttpRequest {
        private final String method;
        private final String url;
        private final Map<String, String> headers;
        private final String body;
        private final int timeoutMs;

        private HttpRequest(Builder b) {
            this.method    = b.method;
            this.url       = b.url;
            this.headers   = Collections.unmodifiableMap(b.headers);
            this.body      = b.body;
            this.timeoutMs = b.timeoutMs;
        }

        @Override public String toString() {
            return method + " " + url + " headers=" + headers.size()
                 + " timeout=" + timeoutMs + "ms";
        }

        static class Builder {
            private String method = "GET";
            private final String url;
            private final Map<String, String> headers = new LinkedHashMap<>();
            private String body;
            private int timeoutMs = 5000;

            Builder(String url) { this.url = url; }

            Builder method(String m)            { this.method = m;    return this; }
            Builder header(String k, String v)  { headers.put(k, v); return this; }
            Builder body(String b)              { this.body = b;     return this; }
            Builder timeout(int ms)             { this.timeoutMs=ms; return this; }
            HttpRequest build()                 { return new HttpRequest(this); }
        }
    }

    public static void main(String[] args) {
        // Singleton
        DatabaseConnection db1 = DatabaseConnection.getInstance();
        DatabaseConnection db2 = DatabaseConnection.getInstance();
        System.out.println("Same instance: " + (db1 == db2)); // true

        // Factory
        for (String type : new String[]{"email", "sms", "push"}) {
            createNotification(type).notify("Hello!");
        }

        // Builder
        HttpRequest req = new HttpRequest.Builder("https://api.example.com/users")
            .method("POST")
            .header("Content-Type", "application/json")
            .header("Authorization", "Bearer token123")
            .body("{\"name\":\"Alice\"}")
            .timeout(3000)
            .build();
        System.out.println(req);
    }
}

import java.lang.reflect.*;
import java.util.*;

public class StructuralPatterns {

    // ── ADAPTER — converts one interface to another ────────────────────
    // Existing interface our code expects
    interface ModernLogger {
        void log(String level, String message);
    }

    // Legacy third-party logger we can't modify
    static class LegacyLogger {
        void writeLog(String msg) { System.out.println("LEGACY: " + msg); }
    }

    // Adapter wraps legacy, exposes modern interface
    static class LegacyLoggerAdapter implements ModernLogger {
        private final LegacyLogger legacy;
        LegacyLoggerAdapter(LegacyLogger l) { this.legacy = l; }

        @Override
        public void log(String level, String message) {
            legacy.writeLog("[" + level + "] " + message); // translate call
        }
    }

    // ── DECORATOR — adds behaviour without subclassing ─────────────────
    interface TextProcessor {
        String process(String text);
    }

    static class PlainText implements TextProcessor {
        public String process(String text) { return text; }
    }

    // Abstract decorator — delegates to wrapped component
    abstract static class TextDecorator implements TextProcessor {
        protected final TextProcessor wrapped;
        TextDecorator(TextProcessor w) { this.wrapped = w; }
    }

    static class TrimDecorator extends TextDecorator {
        TrimDecorator(TextProcessor w) { super(w); }
        public String process(String text) { return wrapped.process(text).trim(); }
    }

    static class UpperCaseDecorator extends TextDecorator {
        UpperCaseDecorator(TextProcessor w) { super(w); }
        public String process(String text) { return wrapped.process(text).toUpperCase(); }
    }

    static class PrefixDecorator extends TextDecorator {
        private final String prefix;
        PrefixDecorator(TextProcessor w, String p) { super(w); this.prefix = p; }
        public String process(String text) { return prefix + wrapped.process(text); }
    }

    // ── PROXY — controls access, adds cross-cutting concerns ───────────
    interface DataService {
        String fetchData(String key);
    }

    static class RealDataService implements DataService {
        public String fetchData(String key) {
            System.out.println("  [DB] Fetching: " + key); // expensive
            return "data_for_" + key;
        }
    }

    // Caching proxy — same interface, transparent to callers
    static class CachingProxy implements DataService {
        private final DataService real;
        private final Map<String, String> cache = new HashMap<>();

        CachingProxy(DataService real) { this.real = real; }

        public String fetchData(String key) {
            if (cache.containsKey(key)) {
                System.out.println("  [Cache HIT] " + key);
                return cache.get(key);
            }
            System.out.println("  [Cache MISS] " + key);
            String result = real.fetchData(key);
            cache.put(key, result);
            return result;
        }
    }

    public static void main(String[] args) {
        // Adapter
        ModernLogger logger = new LegacyLoggerAdapter(new LegacyLogger());
        logger.log("INFO",  "Application started");
        logger.log("ERROR", "Something went wrong");

        // Decorator — compose behaviours like Russian dolls
        TextProcessor pipeline = new PrefixDecorator(
            new UpperCaseDecorator(
                new TrimDecorator(
                    new PlainText())),
            ">> ");
        System.out.println(pipeline.process("  hello world  "));
        // >> HELLO WORLD

        // Proxy
        DataService service = new CachingProxy(new RealDataService());
        System.out.println(service.fetchData("user:42")); // MISS → DB call
        System.out.println(service.fetchData("user:42")); // HIT → cache
        System.out.println(service.fetchData("user:99")); // MISS → DB call
    }
}

