import java.util.*;
import java.util.function.*;

public class BehavioralPatterns {

    // ── STRATEGY — swappable algorithm family ─────────────────────────
    interface SortStrategy<T extends Comparable<T>> {
        void sort(List<T> list);
        default String name() { return getClass().getSimpleName(); }
    }

    static class BubbleSort<T extends Comparable<T>> implements SortStrategy<T> {
        public void sort(List<T> list) {
            int n = list.size();
            for (int i = 0; i < n-1; i++)
                for (int j = 0; j < n-i-1; j++)
                    if (list.get(j).compareTo(list.get(j+1)) > 0) {
                        T tmp = list.get(j);
                        list.set(j, list.get(j+1));
                        list.set(j+1, tmp);
                    }
        }
    }

    static class JavaSort<T extends Comparable<T>> implements SortStrategy<T> {
        public void sort(List<T> list) { Collections.sort(list); }
    }

    static class Sorter<T extends Comparable<T>> {
        private SortStrategy<T> strategy;
        Sorter(SortStrategy<T> s) { this.strategy = s; }
        void setStrategy(SortStrategy<T> s) { this.strategy = s; } // swap at runtime
        void sort(List<T> list) {
            System.out.println("Using: " + strategy.name());
            strategy.sort(list);
        }
    }

    // ── OBSERVER — publish-subscribe ───────────────────────────────────
    interface EventListener<T> {
        void onEvent(T event);
    }

    static class EventBus<T> {
        private final List<EventListener<T>> listeners = new ArrayList<>();

        void subscribe(EventListener<T> l)   { listeners.add(l); }
        void unsubscribe(EventListener<T> l) { listeners.remove(l); }

        void publish(T event) {
            System.out.println("Publishing: " + event);
            listeners.forEach(l -> l.onEvent(event));
        }
    }

    record OrderEvent(String orderId, String status) {}

    // ── COMMAND — encapsulate action as object ─────────────────────────
    interface Command {
        void execute();
        void undo();
    }

    static class TextEditor {
        private final StringBuilder text = new StringBuilder();
        private final Deque<Command> history = new ArrayDeque<>();

        void executeCommand(Command cmd) {
            cmd.execute();
            history.push(cmd);
        }

        void undo() {
            if (!history.isEmpty()) history.pop().undo();
        }

        String getText() { return text.toString(); }

        Command insertCommand(String s) {
            return new Command() {
                public void execute() { text.append(s); }
                public void undo()    { text.delete(text.length()-s.length(), text.length()); }
            };
        }

        Command deleteLastCommand() {
            final String[] deleted = {""};
            return new Command() {
                public void execute() {
                    if (text.length() > 0) {
                        deleted[0] = String.valueOf(text.charAt(text.length()-1));
                        text.deleteCharAt(text.length()-1);
                    }
                }
                public void undo() { text.append(deleted[0]); }
            };
        }
    }

    public static void main(String[] args) {
        // Strategy
        List<Integer> data = new ArrayList<>(Arrays.asList(5,2,8,1,9,3));
        Sorter<Integer> sorter = new Sorter<>(new BubbleSort<>());
        sorter.sort(data);
        System.out.println(data); // [1, 2, 3, 5, 8, 9]
        sorter.setStrategy(new JavaSort<>()); // swap strategy at runtime
        sorter.sort(new ArrayList<>(Arrays.asList(9,1,4)));

        // Observer
        EventBus<OrderEvent> bus = new EventBus<>();
        bus.subscribe(e -> System.out.println("Email: Order " + e.orderId() + " is " + e.status()));
        bus.subscribe(e -> System.out.println("SMS:   Order " + e.orderId() + " is " + e.status()));
        bus.publish(new OrderEvent("ORD-001", "SHIPPED"));

        // Command with undo
        TextEditor editor = new TextEditor();
        editor.executeCommand(editor.insertCommand("Hello"));
        editor.executeCommand(editor.insertCommand(" World"));
        System.out.println(editor.getText()); // Hello World
        editor.undo();
        System.out.println(editor.getText()); // Hello
        editor.undo();
        System.out.println(editor.getText()); // (empty)
    }
}

