STRATEGY:
  interface Strategy { void execute(data) }
  class Context { Strategy s; setStrategy(s); run() → s.execute(data) }
  swap strategy at runtime, context unchanged

OBSERVER:
  class Subject { List<Observer> listeners
    subscribe(o); unsubscribe(o)
    notify(event) → listeners.forEach(o.onEvent(event)) }
  interface Observer { void onEvent(event) }

COMMAND:
  interface Command { execute(); undo() }
  class Invoker { Deque<Command> history
    run(cmd) { cmd.execute(); history.push(cmd) }
    undo()   { history.pop().undo() } }

