import java.util.*;

public class BehavioralPatterns2 {

    // ── TEMPLATE METHOD — skeleton in base class, hooks in subclasses ──
    abstract static class DataMigration {
        // Template method — defines the algorithm skeleton
        final void migrate() {
            connect();
            List<String> data = extract();
            List<String> transformed = transform(data);
            load(transformed);
            disconnect();
        }

        void connect()    { System.out.println("[Base] Connecting..."); }
        void disconnect() { System.out.println("[Base] Disconnecting..."); }

        abstract List<String> extract();
        abstract List<String> transform(List<String> data);
        abstract void load(List<String> data);
    }

    static class CSVMigration extends DataMigration {
        List<String> extract()                { return List.of("a,1", "b,2", "c,3"); }
        List<String> transform(List<String> d){ return d.stream().map(String::toUpperCase).toList(); }
        void load(List<String> d)             { System.out.println("CSV loaded: " + d); }
    }

    static class JSONMigration extends DataMigration {
        List<String> extract()                { return List.of("{id:1}", "{id:2}"); }
        List<String> transform(List<String> d){ return d.stream().map(s -> s.replace("{","[")).toList(); }
        void load(List<String> d)             { System.out.println("JSON loaded: " + d); }
    }

    // ── CHAIN OF RESPONSIBILITY — pass request along a chain ───────────
    abstract static class RequestHandler {
        protected RequestHandler next;

        RequestHandler setNext(RequestHandler n) { this.next = n; return n; }

        abstract boolean handle(int requestLevel, String request);

        protected boolean passToNext(int level, String req) {
            return next != null && next.handle(level, req);
        }
    }

    static class AuthHandler extends RequestHandler {
        boolean handle(int level, String req) {
            if (req.contains("no-auth")) {
                System.out.println("AuthHandler: REJECTED - not authenticated");
                return false;
            }
            System.out.println("AuthHandler: OK");
            return passToNext(level, req);
        }
    }

    static class RateLimitHandler extends RequestHandler {
        private int count = 0;
        boolean handle(int level, String req) {
            if (++count > 3) {
                System.out.println("RateLimitHandler: REJECTED - rate limit exceeded");
                return false;
            }
            System.out.println("RateLimitHandler: OK (" + count + "/3)");
            return passToNext(level, req);
        }
    }

    static class LoggingHandler extends RequestHandler {
        boolean handle(int level, String req) {
            System.out.println("LoggingHandler: logged '" + req + "'");
            return passToNext(level, req);
        }
    }

    // ── STATE — object behaviour changes with state ────────────────────
    interface TrafficLightState {
        void enter();
        TrafficLightState next();
    }

    static class RedState implements TrafficLightState {
        public void enter()             { System.out.println("RED   - Stop!"); }
        public TrafficLightState next() { return new GreenState(); }
    }
    static class GreenState implements TrafficLightState {
        public void enter()             { System.out.println("GREEN - Go!"); }
        public TrafficLightState next() { return new YellowState(); }
    }
    static class YellowState implements TrafficLightState {
        public void enter()             { System.out.println("YELLOW - Slow down!"); }
        public TrafficLightState next() { return new RedState(); }
    }

    static class TrafficLight {
        private TrafficLightState state = new RedState();
        void tick() { state.enter(); state = state.next(); }
    }

    public static void main(String[] args) {
        // Template Method
        System.out.println("=== CSV Migration ===");
        new CSVMigration().migrate();
        System.out.println("=== JSON Migration ===");
        new JSONMigration().migrate();

        // Chain of Responsibility — build chain
        AuthHandler auth = new AuthHandler();
        RateLimitHandler rate = new RateLimitHandler();
        LoggingHandler log = new LoggingHandler();
        auth.setNext(rate).setNext(log);

        System.out.println("\n--- Request 1 (valid) ---");
        auth.handle(1, "GET /users");
        System.out.println("--- Request 2 (no-auth) ---");
        auth.handle(1, "GET /admin no-auth");

        // State Machine
        TrafficLight light = new TrafficLight();
        for (int i = 0; i < 6; i++) light.tick();
        // RED → GREEN → YELLOW → RED → GREEN → YELLOW
    }
}

