import java.util.*;

public class AdvancedPatterns {

    // ── COMPOSITE — tree of objects, uniform interface ─────────────────
    interface UIComponent {
        void render(String indent);
        int getWidth();
    }

    static class Button implements UIComponent {
        private final String label;
        private final int width;
        Button(String label, int width) { this.label=label; this.width=width; }
        public void render(String indent) { System.out.println(indent + "[Button: " + label + "]"); }
        public int getWidth() { return width; }
    }

    static class Panel implements UIComponent {
        private final String name;
        private final List<UIComponent> children = new ArrayList<>();

        Panel(String name) { this.name = name; }
        void add(UIComponent c)    { children.add(c); }
        void remove(UIComponent c) { children.remove(c); }

        public void render(String indent) {
            System.out.println(indent + "[Panel: " + name + "]");
            children.forEach(c -> c.render(indent + "  ")); // recurse
        }
        public int getWidth() { return children.stream().mapToInt(UIComponent::getWidth).max().orElse(0); }
    }

    // ── FACADE — simplified interface to a complex subsystem ───────────
    static class VideoEncoder   { String encode(String f)  { return "encoded:"+f; } }
    static class AudioExtractor { String extract(String f)  { return "audio:"+f; } }
    static class ThumbnailGen   { String generate(String f) { return "thumb:"+f; } }
    static class CloudUploader  { void upload(String asset) { System.out.println("Uploaded: "+asset); } }

    static class VideoProcessingFacade {
        private final VideoEncoder   encoder   = new VideoEncoder();
        private final AudioExtractor extractor = new AudioExtractor();
        private final ThumbnailGen   thumbGen  = new ThumbnailGen();
        private final CloudUploader  uploader  = new CloudUploader();

        // One simple method hides 4 subsystems
        void processVideo(String filename) {
            System.out.println("Processing: " + filename);
            uploader.upload(encoder.encode(filename));
            uploader.upload(extractor.extract(filename));
            uploader.upload(thumbGen.generate(filename));
            System.out.println("Done!");
        }
    }

    // ── FLYWEIGHT — share common state among many objects ──────────────
    // Intrinsic state (shared): character glyph, font
    // Extrinsic state (per-instance): position x, y
    record CharacterGlyph(char c, String font, int size) {} // shared

    static class FlyweightFactory {
        private static final Map<String, CharacterGlyph> pool = new HashMap<>();

        static CharacterGlyph get(char c, String font, int size) {
            String key = c + "|" + font + "|" + size;
            return pool.computeIfAbsent(key, k -> {
                System.out.println("Creating glyph: " + key);
                return new CharacterGlyph(c, font, size);
            });
        }
        static int poolSize() { return pool.size(); }
    }

    static class RenderedChar {
        final CharacterGlyph glyph; // shared — from pool
        final int x, y;            // unique per character on screen
        RenderedChar(char c, String font, int size, int x, int y) {
            this.glyph = FlyweightFactory.get(c, font, size); // reuse
            this.x = x; this.y = y;
        }
        void render() { System.out.println(glyph.c() + " at (" + x + "," + y + ")"); }
    }

    public static void main(String[] args) {
        // Composite UI tree
        Panel root = new Panel("Root");
        Panel toolbar = new Panel("Toolbar");
        toolbar.add(new Button("Save", 80));
        toolbar.add(new Button("Load", 80));
        Panel content = new Panel("Content");
        content.add(new Button("Submit", 120));
        root.add(toolbar);
        root.add(content);
        root.render("");

        // Facade
        new VideoProcessingFacade().processVideo("lecture.mp4");

        // Flyweight — render 'Hello' twice, same glyphs reused
        String text = "HelloHello";
        List<RenderedChar> chars = new ArrayList<>();
        for (int i = 0; i < text.length(); i++)
            chars.add(new RenderedChar(text.charAt(i), "Arial", 12, i*8, 0));
        System.out.println("Pool size: " + FlyweightFactory.poolSize()); // 4 (H,e,l,o)
        // 10 characters rendered, only 4 glyph objects created
    }
}

