import java.util.*;
import java.util.concurrent.*;

public class Q1 {
    static class AppConfig {
        private final Map<String, String> props;

        private AppConfig() {
            props = new HashMap<>();
            props.put("db.host", "localhost");
            props.put("db.port", "5432");
            props.put("app.name", "DevLearn");
        }

        // Initialization-on-demand holder — simplest thread-safe lazy singleton
        private static class Holder {
            static final AppConfig INSTANCE = new AppConfig();
        }

        public static AppConfig getInstance() { return Holder.INSTANCE; }

        public String get(String key) { return props.get(key); }
        public String getOrDefault(String key, String def) { return props.getOrDefault(key, def); }
    }

    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(10);
        Set<Integer> ids = Collections.synchronizedSet(new HashSet<>());
        for (int i = 0; i < 100; i++)
            pool.submit(() -> ids.add(System.identityHashCode(AppConfig.getInstance())));
        pool.shutdown(); pool.awaitTermination(2, TimeUnit.SECONDS);
        System.out.println("Unique instances: " + ids.size()); // 1
        System.out.println(AppConfig.getInstance().get("app.name")); // DevLearn
    }
}

