public class Q3 {
    static class DatabaseQuery {
        private final String table, columns, where, orderBy;
        private final int limit, offset;

        private DatabaseQuery(Builder b) {
            this.table   = b.table;
            this.columns = b.columns;
            this.where   = b.where;
            this.orderBy = b.orderBy;
            this.limit   = b.limit;
            this.offset  = b.offset;
        }

        public String toSQL() {
            StringBuilder sb = new StringBuilder();
            sb.append("SELECT ").append(columns).append(" FROM ").append(table);
            if (where   != null) sb.append(" WHERE ").append(where);
            if (orderBy != null) sb.append(" ORDER BY ").append(orderBy);
            sb.append(" LIMIT ").append(limit).append(" OFFSET ").append(offset);
            return sb.toString();
        }

        static class Builder {
            private final String table;
            private String columns = "*";
            private String where, orderBy;
            private int limit = 100, offset = 0;

            Builder(String table) { this.table = table; }

            Builder columns(String... cols) { this.columns = String.join(",", cols); return this; }
            Builder where(String w)         { this.where   = w;   return this; }
            Builder orderBy(String o)       { this.orderBy = o;   return this; }
            Builder limit(int l)            { this.limit   = l;   return this; }
            Builder offset(int o)           { this.offset  = o;   return this; }

            DatabaseQuery build() {
                if (table == null || table.isBlank())
                    throw new IllegalArgumentException("Table name is required");
                return new DatabaseQuery(this);
            }
        }
    }

    public static void main(String[] args) {
        System.out.println(new DatabaseQuery.Builder("users")
            .columns("id","name","email").where("age > 18")
            .orderBy("name ASC").limit(50).build().toSQL());
        System.out.println(new DatabaseQuery.Builder("products").limit(10).build().toSQL());
        try { new DatabaseQuery.Builder("").build(); }
        catch (IllegalArgumentException e) { System.out.println("Caught: " + e.getMessage()); }
    }
}

