import java.util.*;

public class Q4 {
    interface DataRepository { String findById(int id); }

    static class RealRepository implements DataRepository {
        public String findById(int id) {
            try { Thread.sleep(100); } catch (InterruptedException e) {}
            return "data-" + id;
        }
    }

    static class CachingDecorator implements DataRepository {
        private final DataRepository wrapped;
        private final Map<Integer, String> cache = new HashMap<>();
        CachingDecorator(DataRepository w) { this.wrapped = w; }
        public String findById(int id) {
            if (cache.containsKey(id)) return cache.get(id);
            String result = wrapped.findById(id);
            cache.put(id, result);
            return result;
        }
    }

    static class LoggingDecorator implements DataRepository {
        private final DataRepository wrapped;
        LoggingDecorator(DataRepository w) { this.wrapped = w; }
        public String findById(int id) {
            long start = System.currentTimeMillis();
            String result = wrapped.findById(id);
            System.out.printf("findById(%d) = %s [%dms]%n",
                id, result, System.currentTimeMillis() - start);
            return result;
        }
    }

    public static void main(String[] args) {
        DataRepository repo = new LoggingDecorator(
            new CachingDecorator(new RealRepository()));
        repo.findById(1);
        repo.findById(1);
        repo.findById(2);
    }
}

