import java.util.*;
import java.util.function.*;

public class Q7 {
    static class EventBus<T> {
        private final Map<String, List<Consumer<T>>> handlers = new HashMap<>();

        public void subscribe(String type, Consumer<T> handler) {
            handlers.computeIfAbsent(type, k -> new ArrayList<>()).add(handler);
        }

        public void unsubscribe(String type, Consumer<T> handler) {
            List<Consumer<T>> list = handlers.get(type);
            if (list != null) list.remove(handler);
        }

        public void publish(String type, T event) {
            List<Consumer<T>> list = handlers.getOrDefault(type, List.of());
            new ArrayList<>(list).forEach(h -> h.accept(event)); // copy to avoid CME
        }
    }

    record Order(String id, String customer, double amount) {}

    public static void main(String[] args) {
        EventBus<Order> bus = new EventBus<>();
        Consumer<Order> emailHandler = o -> System.out.println("Email to "+o.customer()+" for order "+o.id());
        Consumer<Order> smsHandler   = o -> System.out.println("SMS to "  +o.customer()+" for order "+o.id());
