import java.util.UUID;

public class Q8 {
    record PaymentResult(boolean success, String transactionId, String message) {}

    interface PaymentStrategy {
        PaymentResult pay(double amount);
        String name();
        double feePercent();
    }

    static class CreditCardStrategy implements PaymentStrategy {
        public double feePercent() { return 2.0; }
        public String name() { return "CreditCard"; }
        public PaymentResult pay(double amount) {
            return new PaymentResult(true, UUID.randomUUID().toString().substring(0,8),
                String.format("Charged $%.2f via Credit Card", amount));
        }
    }
    static class PayPalStrategy implements PaymentStrategy {
        public double feePercent() { return 1.0; }
        public String name() { return "PayPal"; }
        public PaymentResult pay(double amount) {
            return new PaymentResult(true, "PP-" + UUID.randomUUID().toString().substring(0,6),
                String.format("Sent $%.2f via PayPal", amount));
        }
    }
    static class CryptoStrategy implements PaymentStrategy {
        public double feePercent() { return 0.0; }
        public String name() { return "Crypto"; }
        public PaymentResult pay(double amount) {
            return new PaymentResult(true, "0x" + UUID.randomUUID().toString().replace("-","").substring(0,10),
                String.format("Transferred $%.2f in crypto", amount));
        }
    }

    static class PaymentProcessor {
        private PaymentStrategy strategy;
        public void setStrategy(PaymentStrategy s) { this.strategy = s; }
        public PaymentResult processPayment(double base) {
            double total = base * (1 + strategy.feePercent() / 100);
            System.out.printf("  Base: $%.2f  Fee: %.0f%%  Total: $%.2f%n", base, strategy.feePercent(), total);
            return strategy.pay(total);
        }
    }

    public static void main(String[] args) {
        PaymentProcessor p = new PaymentProcessor();
        double order = 100.0;
        for (PaymentStrategy s : new PaymentStrategy[]{
                new CreditCardStrategy(), new PayPalStrategy(), new CryptoStrategy() }) {
            p.setStrategy(s);
            PaymentResult r = p.processPayment(order);
            System.out.println(s.name() + ": " + r.message() + " txn=" + r.transactionId());
        }
    }
}

