import java.util.*;

public class Q9 {
    interface Command { void execute(); void undo(); }

    static class TextBuffer {
        private final StringBuilder buf = new StringBuilder();
        void insert(int pos, String text) { buf.insert(pos, text); }
        void delete(int pos, int len)     { buf.delete(pos, pos + len); }
        String get()                      { return buf.toString(); }
    }

    static class InsertCommand implements Command {
        private final TextBuffer buf; private final int pos; private final String text;
        InsertCommand(TextBuffer b, int p, String t) { buf=b; pos=p; text=t; }
        public void execute() { buf.insert(pos, text); }
        public void undo()    { buf.delete(pos, text.length()); }
    }

    static class DeleteCommand implements Command {
        private final TextBuffer buf; private final int pos, len;
        private String deleted;
        DeleteCommand(TextBuffer b, int p, int l) { buf=b; pos=p; len=l; }
        public void execute() { deleted = buf.get().substring(pos, pos+len); buf.delete(pos, len); }
        public void undo()    { buf.insert(pos, deleted); }
    }

    static class Editor {
        final TextBuffer buf = new TextBuffer();
        private final Deque<Command> undoStack = new ArrayDeque<>();
        private final Deque<Command> redoStack = new ArrayDeque<>();

        public void execute(Command cmd) {
            cmd.execute();
            undoStack.push(cmd);
            redoStack.clear(); // new action invalidates redo history
        }
        public void undo() {
            if (undoStack.isEmpty()) return;
            Command cmd = undoStack.pop();
            cmd.undo();
            redoStack.push(cmd);
        }
        public void redo() {
            if (redoStack.isEmpty()) return;
            Command cmd = redoStack.pop();
            cmd.execute();
            undoStack.push(cmd);
        }
        public String getText() { return buf.get(); }
    }

    public static void main(String[] args) {
        Editor e = new Editor();
        e.execute(new InsertCommand(e.buf, 0, "Hello"));
        e.execute(new InsertCommand(e.buf, 5, " World"));
        System.out.println(e.getText()); // Hello World
        e.undo();
        System.out.println(e.getText()); // Hello
        e.redo();
        System.out.println(e.getText()); // Hello World
        e.execute(new DeleteCommand(e.buf, 5, 6));
        System.out.println(e.getText()); // Hello
        e.undo();
        System.out.println(e.getText()); // Hello World
    }
}

