import java.util.*;
import java.util.stream.*;

public class Q10 {
    abstract static class DataExporter {
        public final void export(List<Map<String, String>> data) {
            validate(data);
            List<String> rows = format(data);
            writeHeader(data.isEmpty() ? List.of() : new ArrayList<>(data.get(0).keySet()));
            writeRows(rows);
            writeFooter(rows.size());
        }
        private void validate(List<Map<String, String>> data) {
            if (data == null || data.isEmpty()) throw new IllegalArgumentException("Data cannot be empty");
        }
        abstract List<String> format(List<Map<String, String>> data);
        abstract void writeHeader(List<String> columns);
        void writeRows(List<String> rows) { rows.forEach(System.out::println); }
        void writeFooter(int count) { System.out.println("-- " + count + " rows --"); }
    }

    static class CSVExporter extends DataExporter {
        void writeHeader(List<String> cols) { System.out.println(String.join(",", cols)); }
        List<String> format(List<Map<String, String>> data) {
            return data.stream()
                .map(row -> String.join(",", row.values()))
                .collect(Collectors.toList());
        }
    }

    static class JSONExporter extends DataExporter {
        void writeHeader(List<String> cols) { System.out.println("["); }
        void writeFooter(int count) { System.out.println("]"); System.out.println("-- " + count + " rows --"); }
        List<String> format(List<Map<String, String>> data) {
            return data.stream().map(row -> {
                String fields = row.entrySet().stream()
                    .map(e -> "\"" + e.getKey() + "\":\"" + e.getValue() + "\"")
                    .collect(Collectors.joining(","));
                return "  {" + fields + "}";
            }).collect(Collectors.toList());
        }
    }

    public static void main(String[] args) {
        var data = List.of(
            new LinkedHashMap<String,String>(){{ put("name","Alice"); put("age","30"); put("city","Delhi"); }},
            new LinkedHashMap<String,String>(){{ put("name","Bob");   put("age","25"); put("city","Mumbai"); }}
        );
        System.out.println("=== CSV ===");
        new CSVExporter().export(data);
