import java.util.*;

public class Q11 {
    record Request(String path, String clientId, Map<String, String> headers) {}
    record Response(int status, String body) {
        public String toString() { return status + " " + body; }
    }

    abstract static class Middleware {
        protected Middleware next;
        Middleware link(Middleware n) { this.next = n; return n; }
        abstract Response handle(Request req);
        protected Response passToNext(Request req) {
            return next != null ? next.handle(req) : new Response(404, "No handler");
        }
    }

    static class AuthMiddleware extends Middleware {
        public Response handle(Request req) {
            if (!req.headers().containsKey("token")) {
                System.out.println("[Auth] REJECTED - no token");
                return new Response(401, "Unauthorized");
            }
            System.out.println("[Auth] OK");
            return passToNext(req);
        }
    }

    static class RateLimitMiddleware extends Middleware {
        private final Map<String, Integer> counts = new HashMap<>();
        private final int maxReqs;
        RateLimitMiddleware(int max) { this.maxReqs = max; }
        public Response handle(Request req) {
            int count = counts.merge(req.clientId(), 1, Integer::sum);
            if (count > maxReqs) {
                System.out.println("[RateLimit] REJECTED - " + req.clientId() + " (" + count + "/" + maxReqs + ")");
                return new Response(429, "Too Many Requests");
            }
            System.out.println("[RateLimit] OK (" + count + "/" + maxReqs + ")");
            return passToNext(req);
        }
    }

    static class LoggingMiddleware extends Middleware {
        public Response handle(Request req) {
            Response resp = passToNext(req);
            System.out.println("[Log] " + req.clientId() + " " + req.path() + " → " + resp.status());
            return resp;
        }
    }

    static class RouteHandler extends Middleware {
        public Response handle(Request req) {
            return new Response(200, "OK: " + req.path());
        }
    }

    public static void main(String[] args) {
        AuthMiddleware auth = new AuthMiddleware();
        RateLimitMiddleware rate = new RateLimitMiddleware(3);
        LoggingMiddleware log = new LoggingMiddleware();
        RouteHandler route = new RouteHandler();
        auth.link(rate).link(log).link(route);

        var headers = Map.of("token", "abc123");
        for (int i = 1; i <= 4; i++) {
            System.out.println("\n=== Request " + i + ": GET /api/data ===");
            System.out.println(auth.handle(new Request("/api/data", "client-1", headers)));
        }
        System.out.println("\n=== No-auth request ===");
        System.out.println(auth.handle(new Request("/api/data", "client-2", Map.of())));
    }
}

