public class Q12 {
    interface OrderState {
        void pay(Order order);
        void process(Order order);
        void ship(Order order, String trackingNo);
        void deliver(Order order);
        String stateName();
    }

    static void invalid(String action, String state) {
        throw new IllegalStateException("Cannot " + action + " when order is " + state);
    }

    static class PendingState implements OrderState {
        public void pay(Order o) { System.out.println("Payment received for " + o.orderId); o.setState(new PaidState()); }
        public void process(Order o) { invalid("process", stateName()); }
        public void ship(Order o, String t) { invalid("ship", stateName()); }
        public void deliver(Order o) { invalid("deliver", stateName()); }
        public String stateName() { return "PENDING"; }
    }
    static class PaidState implements OrderState {
        public void pay(Order o) { invalid("pay", stateName()); }
        public void process(Order o) { System.out.println("Processing " + o.orderId); o.setState(new ProcessingState()); }
        public void ship(Order o, String t) { invalid("ship", stateName()); }
        public void deliver(Order o) { invalid("deliver", stateName()); }
        public String stateName() { return "PAID"; }
    }
    static class ProcessingState implements OrderState {
        public void pay(Order o) { invalid("pay", stateName()); }
        public void process(Order o) { invalid("process", stateName()); }
        public void ship(Order o, String t) {
            System.out.println("Shipping " + o.orderId + " tracking=" + t);
            o.trackingNumber = t; o.setState(new ShippedState());
        }
        public void deliver(Order o) { invalid("deliver", stateName()); }
        public String stateName() { return "PROCESSING"; }
    }
    static class ShippedState implements OrderState {
        public void pay(Order o) { invalid("pay", stateName()); }
        public void process(Order o) { invalid("process", stateName()); }
        public void ship(Order o, String t) { invalid("ship", stateName()); }
        public void deliver(Order o) { System.out.println("Delivered " + o.orderId); o.setState(new DeliveredState()); }
        public String stateName() { return "SHIPPED"; }
    }
    static class DeliveredState implements OrderState {
        public void pay(Order o) { invalid("pay", stateName()); }
        public void process(Order o) { invalid("process", stateName()); }
        public void ship(Order o, String t) { invalid("ship", stateName()); }
        public void deliver(Order o) { invalid("deliver", stateName()); }
        public String stateName() { return "DELIVERED"; }
    }

    static class Order {
        private OrderState currentState;
        String trackingNumber;
        final String orderId;
        Order(String id) { orderId = id; currentState = new PendingState(); }
        void setState(OrderState s) { this.currentState = s; }
        String getState() { return currentState.stateName(); }
        public void pay()                   { currentState.pay(this); }
        public void process()               { currentState.process(this); }
        public void ship(String t)          { currentState.ship(this, t); }
        public void deliver()               { currentState.deliver(this); }
        public String toString() { return orderId+" ["+getState()+"]"+(trackingNumber!=null?" tracking="+trackingNumber:""); }
    }

    public static void main(String[] args) {
        Order order = new Order("ORD-001");
        System.out.println(order);
        order.pay();     System.out.println(order);
        order.process(); System.out.println(order);
        order.ship("FEDEX-123456"); System.out.println(order);
        order.deliver(); System.out.println(order);
        try { order.pay(); }
        catch (IllegalStateException e) { System.out.println("Error: " + e.getMessage()); }
    }
}

