import java.util.*;

public class Q13 {
    interface FileSystemItem {
        String getName();
        long getSize();
        void print(String indent);
    }

    static class File implements FileSystemItem {
        private final String name; private final long size;
        File(String name, long size) { this.name=name; this.size=size; }
        public String getName() { return name; }
        public long getSize()   { return size; }
        public void print(String indent) {
            System.out.printf("%s%-20s %6d bytes%n", indent, name, size);
        }
    }

    static class Directory implements FileSystemItem {
        private final String name;
        private final List<FileSystemItem> children = new ArrayList<>();
        Directory(String name) { this.name = name; }
        public void addItem(FileSystemItem item) { children.add(item); }
        public String getName() { return name; }
        public long getSize() { return children.stream().mapToLong(FileSystemItem::getSize).sum(); }
        public void print(String indent) {
            System.out.printf("%s[%s/] %d bytes%n", indent, name, getSize());
            children.forEach(c -> c.print(indent + "  "));
        }
    }

    public static void main(String[] args) {
        Directory root = new Directory("root");
        Directory src  = new Directory("src");
        src.addItem(new File("Main.java",  1024));
        src.addItem(new File("Utils.java",  512));
        Directory docs = new Directory("docs");
        docs.addItem(new File("README.md", 256));
        root.addItem(src);
        root.addItem(docs);
        root.addItem(new File("build.gradle", 128));

        root.print("");
        System.out.println("Total: " + root.getSize() + " bytes");
    }
}

