import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

public class Q14 {
    record ParticleType(String color, String shape, String texture) {
        void render(int x, int y, double velocity) {}
    }

    static class ParticleFactory {
        private static final Map<String, ParticleType> pool = new HashMap<>();

        static ParticleType get(String color, String shape, String texture) {
            String key = color + "|" + shape + "|" + texture;
            return pool.computeIfAbsent(key, k -> {
                System.out.println("Creating particle type: " + key);
                return new ParticleType(color, shape, texture);
            });
        }
        static int poolSize() { return pool.size(); }
    }

    static class Particle {
        private final ParticleType type;
        private int x, y;
        private double velocity;
        Particle(ParticleType type, int x, int y, double velocity) {
            this.type=type; this.x=x; this.y=y; this.velocity=velocity;
        }
        void update() { y += velocity; }
    }

    public static void main(String[] args) {
        String[] colors  = {"red","blue","green","yellow","purple"};
        String[] shapes  = {"circle","circle","square","circle","triangle"};
        String[] textures= {"spark","smoke","fire","sparkle","glow"};

        int N = 10_000;
        List<Particle> particles = new ArrayList<>(N);
        ThreadLocalRandom rnd = ThreadLocalRandom.current();
        for (int i = 0; i < N; i++) {
            int t = rnd.nextInt(5);
            ParticleType type = ParticleFactory.get(colors[t], shapes[t], textures[t]);
            particles.add(new Particle(type, rnd.nextInt(1920), rnd.nextInt(1080), rnd.nextDouble(1,5)));
        }
        System.out.println("\nTotal particles:      " + particles.size());
        System.out.println("Unique particle types: " + ParticleFactory.poolSize());
        System.out.printf("Memory per type (intrinsic):  ~3 String refs%n");
        System.out.printf("Memory per particle (extrinsic): x,y,velocity + 1 ref%n");
        System.out.printf("Without flyweight: %d ParticleType objects%n", N);
        System.out.printf("With    flyweight: %d ParticleType objects%n", ParticleFactory.poolSize());
        System.out.printf("Memory saving: %.1f%%%n", (1.0 - (double)ParticleFactory.poolSize()/N)*100);
    }
}

