import java.util.*;

public class Q15 {
    abstract static class Shape implements Cloneable {
        protected String color;
        Shape(String color) { this.color = color; }
        abstract double area();
        public abstract Shape clone();
    }

    static class Circle extends Shape {
        private double radius;
        Circle(double r, String color) { super(color); this.radius = r; }
        public double area() { return Math.PI * radius * radius; }
        public Circle clone() { return new Circle(radius, color); }
        public String toString() { return "Circle(r=" + radius + ", color=" + color + ", area=" + String.format("%.2f",area()) + ")"; }
        public void setRadius(double r) { this.radius = r; }
    }

    static class Rectangle extends Shape {
        private double width, height;
        Rectangle(double w, double h, String color) { super(color); this.width=w; this.height=h; }
        public double area() { return width * height; }
        public Rectangle clone() { return new Rectangle(width, height, color); }
        public String toString() { return "Rect("+width+"x"+height+", color="+color+", area="+area()+")"; }
        public void setColor(String c) { this.color = c; }
    }

    static class ShapeRegistry {
        private final Map<String, Shape> prototypes = new HashMap<>();
        void register(String name, Shape s) { prototypes.put(name, s); }
        Shape clone(String name) {
            Shape proto = prototypes.get(name);
            if (proto == null) throw new IllegalArgumentException("Unknown shape: " + name);
            return proto.clone();
        }
    }

    public static void main(String[] args) {
        ShapeRegistry registry = new ShapeRegistry();
        registry.register("small-circle", new Circle(5.0, "red"));
        registry.register("card", new Rectangle(10.0, 7.0, "blue"));

        Circle c1 = (Circle) registry.clone("small-circle");
        Circle c2 = (Circle) registry.clone("small-circle");
        System.out.println("c1: " + c1);
        c1.setRadius(10.0); // modify clone — should not affect c2 or prototype
        System.out.println("c1 after modify: " + c1);
        System.out.println("c2 unchanged:    " + c2);
        System.out.println("prototype:       " + registry.clone("small-circle"));

        Rectangle r = (Rectangle) registry.clone("card");
        r.setColor("green");
        System.out.println("Clone: " + r);
        System.out.println("Proto: " + registry.clone("card"));
    }
}

