import java.util.*;

public class Q16 {
    static class ServiceException extends Exception {
        ServiceException(String msg) { super(msg); }
    }

    static class InventoryService {
        public void reserve(String productId, int qty) throws ServiceException {
            System.out.println("[Inventory] Reserved " + qty + " of " + productId);
        }
        public void release(String productId, int qty) {
            System.out.println("[Inventory] Released " + qty + " of " + productId);
        }
    }

    static class PaymentService {
        private final boolean shouldFail;
        PaymentService(boolean fail) { this.shouldFail = fail; }
        public String charge(String customerId, double amount) throws ServiceException {
            if (shouldFail) throw new ServiceException("Payment declined");
            System.out.println("[Payment] Charged $" + amount + " to " + customerId);
            return "TXN-" + UUID.randomUUID().toString().substring(0,8);
        }
    }

    static class ShippingService {
        public String schedule(String orderId, String address) {
            System.out.println("[Shipping] Scheduled delivery to " + address);
            return "SHIP-" + orderId.substring(0,4);
        }
    }

    record OrderConfirmation(String orderId, String txnId, String trackingId) {}

    static class CheckoutFacade {
        private final InventoryService inventory;
        private final PaymentService   payment;
        private final ShippingService  shipping;

        CheckoutFacade(InventoryService inv, PaymentService pay, ShippingService ship) {
            inventory = inv; payment = pay; shipping = ship;
        }

        public OrderConfirmation checkout(String customerId, String productId,
                int qty, double amount, String address) throws ServiceException {
            String orderId = UUID.randomUUID().toString().substring(0,8).toUpperCase();
            // Step 1: reserve inventory
            inventory.reserve(productId, qty);
            // Step 2: charge payment (compensate on failure)
            String txnId;
            try {
                txnId = payment.charge(customerId, amount);
            } catch (ServiceException e) {
                inventory.release(productId, qty); // compensating transaction
                throw new ServiceException("Checkout failed: " + e.getMessage());
            }
            // Step 3: schedule shipping
            String trackingId = shipping.schedule(orderId, address);
            System.out.println("[Checkout] SUCCESS order=" + orderId);
            return new OrderConfirmation(orderId, txnId, trackingId);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== SUCCESS ===");
        try {
            OrderConfirmation conf = new CheckoutFacade(
                new InventoryService(), new PaymentService(false), new ShippingService())
                .checkout("cust-1", "prod-A", 2, 199.99, "123 Main St");
            System.out.println("Confirmed: " + conf);
        } catch (ServiceException e) { System.out.println("Error: " + e.getMessage()); }

        System.out.println("\n=== PAYMENT FAILURE ===");
        try {
            new CheckoutFacade(
                new InventoryService(), new PaymentService(true), new ShippingService())
                .checkout("cust-2", "prod-B", 1, 49.99, "456 Oak Ave");
        } catch (ServiceException e) { System.out.println("Error: " + e.getMessage()); }
    }
}

