    static GUIFactory selectFactory(String os) {
        return switch (os) {
            case "Windows" -> new WindowsFactory();
            case "macOS"   -> new MacFactory();
            default        -> new LinuxFactory();
        };
    }

    public static void main(String[] args) {
        for (String os : new String[]{"Windows","macOS","Linux"}) {
            System.out.println("\n=== " + os + " ===");
            new Application(selectFactory(os)).buildUI();
        }
    }
}

