problems.solutionCode:
import java.util.regex.*;

public class Q18 {
    record ValidationResult(boolean valid, String message) {
        static ValidationResult ok()           { return new ValidationResult(true, ""); }
        static ValidationResult error(String m) { return new ValidationResult(false, m); }
    }

    interface Validator<T> { ValidationResult validate(T input); }

    static class NotNullValidator implements Validator<String> {
        public ValidationResult validate(String s) {
            return s == null ? ValidationResult.error("must not be null") : ValidationResult.ok();
        }
    }

    abstract static class StringDecorator implements Validator<String> {
        protected final Validator<String> wrapped;
        StringDecorator(Validator<String> w) { this.wrapped = w; }
    }

    static class TrimmedValidator extends StringDecorator {
        TrimmedValidator(Validator<String> w) { super(w); }
        public ValidationResult validate(String s) {
            return wrapped.validate(s == null ? null : s.trim());
        }
    }

    static class MinLengthValidator extends StringDecorator {
        private final int min;
        MinLengthValidator(int min, Validator<String> w) { super(w); this.min=min; }
        public ValidationResult validate(String s) {
            ValidationResult r = wrapped.validate(s);
            if (!r.valid()) return r;
            return s.length() < min ? ValidationResult.error("min length is " + min) : ValidationResult.ok();
        }
    }

    static class MaxLengthValidator extends StringDecorator {
        private final int max;
        MaxLengthValidator(int max, Validator<String> w) { super(w); this.max=max; }
        public ValidationResult validate(String s) {
            ValidationResult r = wrapped.validate(s);
            if (!r.valid()) return r;
            return s.length() > max ? ValidationResult.error("max length is " + max) : ValidationResult.ok();
        }
    }

    static class RegexValidator extends StringDecorator {
        private final Pattern pattern;
        RegexValidator(Validator<String> w, String regex) { super(w); this.pattern = Pattern.compile(regex); }
        public ValidationResult validate(String s) {
            ValidationResult r = wrapped.validate(s);
            if (!r.valid()) return r;
            return pattern.matcher(s).matches()
                ? ValidationResult.ok()
                : ValidationResult.error("does not match pattern " + pattern);
        }
    }

    public static void main(String[] args) {
        Validator<String> usernameValidator = new TrimmedValidator(
            new RegexValidator(
                new MaxLengthValidator(20,
                    new MinLengthValidator(3,
                        new NotNullValidator())),
                "[a-zA-Z0-9_]+"));

        String[] inputs = {null, "", "ab", "valid_user123", "invalid user!", "a".repeat(25)};
        for (String input : inputs) {
            ValidationResult r = usernameValidator.validate(input);
            System.out.printf("'%s' → %s%n",
                input==null?"null":input.length()>15?input.substring(0,12)+"...":input,
                r.valid() ? "✓ valid" : "✗ " + r.message());
        }
    }
}

