import java.util.*;
import java.util.regex.*;

public class Q19 {
    static final class User {
        private final String   id;
        private final String   username;
        private final String   email;
        private final int      age;
        private final Set<String> roles;
        private final String   bio;

        private User(Builder b) {
            this.id       = UUID.randomUUID().toString();
            this.username = b.username;
            this.email    = b.email;
            this.age      = b.age;
            this.roles    = Collections.unmodifiableSet(new HashSet<>(b.roles));
            this.bio      = b.bio;
        }

        public String getId()       { return id; }
        public String getUsername() { return username; }
        public String getEmail()    { return email; }
        public int    getAge()      { return age; }
        public Set<String> getRoles(){ return roles; }
        public String getBio()      { return bio; }

        public static class Builder {
            private String   username;
            private String   email;
            private int      age = -1;
            private Set<String> roles = new HashSet<>();
            private String   bio;

            public Builder username(String u) { this.username=u; return this; }
            public Builder email(String e)    { this.email=e;    return this; }
            public Builder age(int a)         { this.age=a;      return this; }
            public Builder roles(Set<String> r){ this.roles=r;   return this; }
            public Builder bio(String b)      { this.bio=b;      return this; }

            public User build() {
                List<String> errors = new ArrayList<>();
                if (username == null || username.length() < 3 || username.length() > 20)
                    errors.add("username must be 3-20 chars");
                Pattern emailPat = Pattern.compile("^[\\w._%+-]+@[\\w.-]+\\.[a-zA-Z]{2,}$");
                if (email == null || !emailPat.matcher(email).matches())
                    errors.add("email is invalid");
                if (age < 18 || age > 120)
                    errors.add("age must be 18-120");
                if (bio != null && bio.length() > 500)
                    errors.add("bio max 500 chars");
                if (!errors.isEmpty())
                    throw new IllegalArgumentException(String.join("\n", errors));
                return new User(this);
            }
        }
    }

    public static void main(String[] args) {
        User user = new User.Builder()
            .username("alice123").email("alice@example.com")
            .age(28).roles(Set.of("USER","EDITOR")).bio("Java developer").build();
        System.out.println(user.getUsername() + " " + user.getRoles());

        try {
            new User.Builder().username("ab").email("bad-email").age(15).build();
        } catch (IllegalArgumentException e) {
            System.out.println("Errors:\n" + e.getMessage());
        }
    }
}

