import java.util.*;
import java.util.function.*;

public class Q20 {
    // ── CREATIONAL: Factory ───────────────────────────────────────────
    interface ReportGenerator { String generate(List<String> data); String format(); }

    static class CSVGenerator implements ReportGenerator {
        public String format() { return "CSV"; }
        public String generate(List<String> data) { return String.join(",", data); }
    }
    static class JSONGenerator implements ReportGenerator {
        public String format() { return "JSON"; }
        public String generate(List<String> data) {
            return "{\"items\":[" + data.stream().map(s->"\"" + s + "\"").reduce((a,b)->a+","+b).orElse("") + "]}";
        }
    }

    static class ReportFactory {
        private final Map<String, Supplier<ReportGenerator>> registry = new HashMap<>();
        ReportFactory() {
            registry.put("csv",  CSVGenerator::new);
            registry.put("json", JSONGenerator::new);
        }
        void register(String fmt, Supplier<ReportGenerator> s) { registry.put(fmt.toLowerCase(), s); }
        ReportGenerator create(String fmt) {
            Supplier<ReportGenerator> s = registry.get(fmt.toLowerCase());
            if (s==null) throw new IllegalArgumentException("Unknown format: " + fmt);
            return s.get();
        }
    }

    // ── STRUCTURAL: Decorator ─────────────────────────────────────────
    static class LoggingDecorator implements ReportGenerator {
        private final ReportGenerator wrapped;
        LoggingDecorator(ReportGenerator w) { this.wrapped = w; }
        public String format() { return wrapped.format(); }
        public String generate(List<String> data) {
            long start = System.currentTimeMillis();
            String result = wrapped.generate(data);
            System.out.printf("[Log] %s report generated in %dms (%d chars)%n",
                format(), System.currentTimeMillis()-start, result.length());
            return result;
        }
    }

    // ── BEHAVIORAL: Observer ──────────────────────────────────────────
    record ReportEvent(String format, String reportId, int chars) {}

    static class ReportEventBus {
        private final List<Consumer<ReportEvent>> listeners = new ArrayList<>();
        void subscribe(Consumer<ReportEvent> l) { listeners.add(l); }
        void publish(ReportEvent e) { listeners.forEach(l -> l.accept(e)); }
    }

    // Report service combining all three patterns
    static class ReportService {
        private final ReportFactory factory;
        private final ReportEventBus bus;

        ReportService(ReportFactory f, ReportEventBus b) { factory=f; bus=b; }

        String generateReport(String format, List<String> data) {
            ReportGenerator gen = new LoggingDecorator(factory.create(format)); // Factory + Decorator
            String result = gen.generate(data);
            bus.publish(new ReportEvent(format, UUID.randomUUID().toString().substring(0,8), result.length())); // Observer
            return result;
        }
    }

    public static void main(String[] args) {
        ReportFactory factory = new ReportFactory();
        ReportEventBus bus = new ReportEventBus();

        // Subscribe observers
        bus.subscribe(e -> System.out.println("[Audit] Report " + e.reportId() + " format=" + e.format()));
        bus.subscribe(e -> System.out.println("[Email] Notifying admin: " + e.chars() + " char report ready"));

        ReportService service = new ReportService(factory, bus);
        var data = List.of("Alice","Bob","Carol");

        System.out.println("=== CSV Report ===");
        System.out.println(service.generateReport("csv",  data));
        System.out.println("=== JSON Report ===");
        System.out.println(service.generateReport("json", data));

        // Plugin: add XML at runtime — zero factory changes
        factory.register("xml", () -> d -> "<items>" + String.join("", d.stream().map(s->"<item>"+s+"</item>").toArray(String[]::new)) + "</items>");
        System.out.println("=== XML Report (plugin) ===");
        System.out.println(service.generateReport("xml",  data));
    }
}
